import { z } from 'zod';

// Secret Vault schemas
export const CreateSecretCollectionSchema = z.object({
  name: z.string().min(1).max(100),
  description: z.string().max(500).optional(),
  tags: z.array(z.string().max(50)).max(20).optional(),
  secrets: z.record(z.string(), z.string()),
});

export const UpdateSecretCollectionSchema = z.object({
  id: z.string(),
  updates: z.object({
    name: z.string().min(1).max(100).optional(),
    description: z.string().max(500).nullable().optional(),
    tags: z.array(z.string().max(50)).max(20).optional(),
    secrets: z.record(z.string(), z.string()).optional(),
  }),
});

export const SecretCollectionIdSchema = z.object({
  id: z.string(),
});

export const ImportEnvFileSchema = z.object({
  name: z.string().min(1).max(100),
  description: z.string().max(500).optional(),
  tags: z.array(z.string().max(50)).max(20).optional(),
  envContent: z.string(),
});

// ============ One-Click Install Schemas ============

export const OneClickTemplateIdSchema = z.object({
  templateId: z.string(),
});

export const OneClickPrereqSchema = z.object({
  serverId: z.string(),
  templateId: z.string(),
});

export const OneClickInstallSchema = z.object({
  serverId: z.string(),
  templateId: z.string(),
});

export const OneClickSendInputSchema = z.object({
  installationId: z.string(),
  input: z.string(),
});

export const OneClickServerIdSchema = z.object({
  serverId: z.string(),
});

export const OneClickInstallationIdSchema = z.object({
  serverId: z.string(),
  installationId: z.string(),
});

export const OneClickLogsSchema = z.object({
  serverId: z.string(),
  installationId: z.string(),
  lines: z.number().optional(),
});

export const OneClickExecuteActionSchema = z.object({
  serverId: z.string(),
  installationId: z.string(),
  actionId: z.string(),
  inputs: z.record(z.string(), z.string()).optional(),
});

export const OneClickGetActionOptionsSchema = z.object({
  serverId: z.string(),
  templateId: z.string(),
  actionId: z.string(),
  inputName: z.string(),
});
